"""Real MCP baseline, generated by FastMCP from the pet-zoo app.

Instead of our hand-rolled `openapi_full`, this builds an actual MCP server with
`FastMCP.from_fastapi(app)` and measures the tool schemas it really exposes. It
grounds the baseline against what a production OpenAPI->MCP generator emits.

Two things make a real MCP server heavier than our hand-rolled baseline:
* longer auto-generated names (`create_animal_monkeys_post`);
* an `outputSchema` per tool by default (the full Animal schema), which clients
  may forward into context. We report that as an extra bucket-A row.

The primary row counts the Anthropic `tools=` shape (name + description +
input_schema), apples-to-apples with the other variants.
"""

from __future__ import annotations

import asyncio

import spec_source as s

from .base import Definitions, PerCallVariant, dumps

_mcp_tools = None  # cached list[mcp.types.Tool]


def _load():
    global _mcp_tools
    if _mcp_tools is None:
        try:
            from fastmcp import FastMCP
        except ImportError as exc:  # pragma: no cover
            raise RuntimeError("mcp_fastmcp variant needs `pip install fastmcp`") from exc
        mcp = FastMCP.from_fastapi(s.app)
        _mcp_tools = [t.to_mcp_tool() for t in asyncio.run(mcp.list_tools())]
    return _mcp_tools


def _anthropic_shape(mt) -> dict:
    return {"name": mt.name, "description": mt.description or "", "input_schema": mt.inputSchema}


class McpFastMCP(PerCallVariant):
    name = "mcp_fastmcp"

    def definitions(self) -> Definitions:
        return Definitions(tools=[_anthropic_shape(mt) for mt in _load()])

    def extra_definitions(self) -> dict[str, Definitions]:
        # Same input tools, plus every outputSchema as forwarded context.
        out_schemas = [mt.outputSchema for mt in _load() if mt.outputSchema]
        return {
            "mcp_fastmcp (+outputSchema)": Definitions(
                tools=[_anthropic_shape(mt) for mt in _load()],
                text=dumps(out_schemas),
            )
        }

    def call_id(self, op: s.Op) -> str:
        # FastMCP keeps the operationId for no-path-param ops and trims the
        # `__param__method` suffix for the rest; match by exact name or prefix.
        oid = op.raw["operationId"]
        for mt in _load():
            if oid == mt.name or oid.startswith(mt.name + "__"):
                return mt.name
        raise KeyError(oid)

    def op_for_name(self, name: str) -> s.Op:
        for op in s.list_operations():
            if self.call_id(op) == name:
                return op
        raise KeyError(name)
